.darma-loader-uiverse-search-signal-bars {
  display: flex;
  align-items: center;
  justify-content: center;
}
.darma-loader-uiverse-search-signal-bars__MiniContainer {
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  width: 130px;
  height: fit-content;
}
.darma-loader-uiverse-search-signal-bars__barContainer {
  width: 100%;
  height: fit-content;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: center;
  gap: 10px;
  background-position: left;
}
.darma-loader-uiverse-search-signal-bars__bar {
  width: 100%;
  height: 8px;
  background: linear-gradient(
    to right,
    rgb(161, 94, 255),
    rgb(217, 190, 255),
    rgb(161, 94, 255)
  );
  background-size: 200% 100%;
  border-radius: 10px;
  animation: darma-loader-uiverse-darma-loader-uiverse-search-signal-bars-search-signal-bars-bar ease-in-out 3s infinite alternate-reverse;
}
@keyframes darma-loader-uiverse-search-signal-bars-bar {
  0% {
    background-position: left;
  }
  100% {
    background-position: right;
  }
}
.darma-loader-uiverse-search-signal-bars__bar2 {
  width: 50%;
}
.darma-loader-uiverse-search-signal-bars__svgIcon {
  position: absolute;
  left: -25px;
  margin-top: 18px;
  z-index: 2;
  width: 70%;
  animation: darma-loader-uiverse-search-signal-bars-search ease-in-out 3s infinite alternate-reverse;
}
@keyframes darma-loader-uiverse-search-signal-bars-search {
  0% {
    transform: translateX(0%) rotate(70deg);
  }

100% {
transform: translateX(100px) rotate(10deg);
}
}
.darma-loader-uiverse-search-signal-bars__svgIcon circle,
line {
stroke: rgb(162, 55, 255);
}
.darma-loader-uiverse-search-signal-bars__svgIcon circle {
fill: rgba(98, 65, 142, 0.238);
}

